     1→//! Crate health check composite tool
     2→
     3→use std::sync::Arc;
     4→
     5→use chrono::Utc;
     6→use schemars::JsonSchema;
     7→use serde::Deserialize;
     8→use tower_mcp::{
     9→    CallToolResult, ResultExt, Tool, ToolBuilder,
    10→    extract::{Json, State},
    11→};
    12→
    13→use crate::state::{AppState, format_number};
    14→
    15→/// Input for crate health check
    16→#[derive(Debug, Deserialize, JsonSchema)]
    17→pub struct HealthCheckInput {
    18→    /// Crate name to evaluate
    19→    name: String,
    20→    /// Version to check (default: latest)
    21→    version: Option<String>,
    22→}
    23→
    24→pub fn build(state: Arc<AppState>) -> Tool {
    25→    ToolBuilder::new("crate_health_check")
    26→        .title("Crate Health Check")
    27→        .description(
    28→            "Comprehensive health check for a crate. Combines multiple API calls into a single \
    29→             report covering maturity, adoption, maintenance, security, compatibility, and \
    30→             dependency weight. Answers: \"should I use this crate?\"",
    31→        )
    32→        .read_only()
    33→        .idempotent()
    34→        .icon("https://crates.io/assets/cargo.png")
    35→        .extractor_handler(
    36→            state,
    37→            |State(state): State<Arc<AppState>>, Json(input): Json<HealthCheckInput>| async move {
    38→                // 1. Get crate info (basic metadata + version list)
    39→                let crate_response = state
    40→                    .client
    41→                    .get_crate(&input.name)
    42→                    .await
    43→                    .tool_context("Crates.io API error")?;
    44→
    45→                let crate_data = &crate_response.crate_data;
    46→                let version = input
    47→                    .version
    48→                    .as_deref()
    49→                    .unwrap_or(&crate_data.max_version)
    50→                    .to_string();
    51→
    52→                // 2. Get version details (license, MSRV)
    53→                let version_detail = state
    54→                    .client
    55→                    .crate_version(&input.name, &version)
    56→                    .await
    57→                    .tool_context("Crates.io API error")?;
    58→
    59→                // 3. Get dependencies
    60→                let deps = state
    61→                    .client
    62→                    .crate_dependencies(&input.name, &version)
    63→                    .await
    64→                    .tool_context("Crates.io API error")?;
    65→
    66→                let normal_deps: Vec<_> = deps.iter().filter(|d| d.kind == "normal").collect();
    67→                let normal_required: Vec<_> = normal_deps.iter().filter(|d| !d.optional).collect();
    68→                let normal_optional: Vec<_> = normal_deps.iter().filter(|d| d.optional).collect();
    69→                let build_deps: Vec<_> = deps.iter().filter(|d| d.kind == "build").collect();
    70→
    71→                // 4. Get reverse dependencies (adoption signal)
    72→                let rev_deps = state
    73→                    .client
    74→                    .crate_reverse_dependencies(&input.name)
    75→                    .await
    76→                    .tool_context("Crates.io API error")?;
    77→
    78→                // 5. Check vulnerabilities via OSV
    79→                let self_vulns = state
    80→                    .osv_client
    81→                    .query_package_any(&input.name)
    82→                    .await
    83→                    .tool_context("OSV.dev API error")?;
    84→
    85→                let vuln_count = self_vulns.vulns.as_ref().map_or(0, |v| v.len());
    86→
    87→                // -- Compute derived metrics --
    88→
    89→                let now = Utc::now();
    90→                let age_days = (now - crate_data.created_at).num_days();
    91→                let days_since_update = (now - crate_data.updated_at).num_days();
    92→                let total_versions = crate_response.versions.len();
    93→
    94→                // Release cadence: average days between releases
    95→                let cadence = if total_versions > 1 {
    96→                    let first = crate_response
    97→                        .versions
    98→                        .last()
    99→                        .map(|v| v.created_at)
   100→                        .unwrap_or(crate_data.created_at);
   101→                    let latest = crate_response
   102→                        .versions
   103→                        .first()
   104→                        .map(|v| v.created_at)
   105→                        .unwrap_or(crate_data.updated_at);
   106→                    let span = (latest - first).num_days();
   107→                    Some(span / (total_versions as i64 - 1))
   108→                } else {
   109→                    None
   110→                };
   111→
   112→                let yanked_count = crate_response.versions.iter().filter(|v| v.yanked).count();
   113→
   114→                // -- Format output --
   115→
   116→                let mut output = format!("# Health Check: {} v{}\n\n", input.name, version);
   117→
   118→                // Description
   119→                if let Some(desc) = &crate_data.description {
   120→                    output.push_str(&format!("> {}\n\n", desc));
   121→                }
   122→
   123→                // Maturity
   124→                output.push_str("## Maturity\n\n");
   125→                let age_str = if age_days > 365 {
   126→                    format!("{:.1} years", age_days as f64 / 365.0)
   127→                } else {
   128→                    format!("{} days", age_days)
   129→                };
   130→                output.push_str(&format!("- **Age**: {}\n", age_str));
   131→                output.push_str(&format!("- **Total versions**: {}\n", total_versions));
   132→                if let Some(c) = cadence {
   133→                    output.push_str(&format!("- **Avg release cadence**: {} days\n", c));
   134→                }
   135→                if yanked_count > 0 {
   136→                    output.push_str(&format!("- **Yanked versions**: {}\n", yanked_count));
   137→                }
   138→
   139→                // Adoption
   140→                output.push_str("\n## Adoption\n\n");
   141→                output.push_str(&format!(
   142→                    "- **Total downloads**: {}\n",
   143→                    format_number(crate_data.downloads)
   144→                ));
   145→                if let Some(recent) = crate_data.recent_downloads {
   146→                    output.push_str(&format!(
   147→                        "- **Recent downloads**: {}\n",
   148→                        format_number(recent)
   149→                    ));
   150→                }
   151→                output.push_str(&format!(
   152→                    "- **Reverse dependencies**: {}\n",
   153→                    rev_deps.meta.total
   154→                ));
   155→
   156→                // Maintenance
   157→                output.push_str("\n## Maintenance\n\n");
   158→                let freshness = if days_since_update <= 30 {
   159→                    "Active (updated within 30 days)"
   160→                } else if days_since_update <= 90 {
   161→                    "Recent (updated within 90 days)"
   162→                } else if days_since_update <= 365 {
   163→                    "Aging (no update in 3-12 months)"
   164→                } else {
   165→                    "Stale (no update in over a year)"
   166→                };
   167→                output.push_str(&format!("- **Status**: {}\n", freshness));
   168→                output.push_str(&format!(
   169→                    "- **Last updated**: {} ({} days ago)\n",
   170→                    crate_data.updated_at.date_naive(),
   171→                    days_since_update
   172→                ));
   173→
   174→                // Security
   175→                output.push_str("\n## Security\n\n");
   176→                if vuln_count == 0 {
   177→                    output.push_str("- **Known vulnerabilities**: None\n");
   178→                } else {
   179→                    output.push_str(&format!(
   180→                        "- **Known vulnerabilities**: {} (run `audit_dependencies` for details)\n",
   181→                        vuln_count
   182→                    ));
   183→                }
   184→
   185→                // Compatibility
   186→                output.push_str("\n## Compatibility\n\n");
   187→                output.push_str(&format!(
   188→                    "- **License**: {}\n",
   189→                    version_detail.license.as_deref().unwrap_or("Not specified")
   190→                ));
   191→                output.push_str(&format!(
   192→                    "- **MSRV**: {}\n",
   193→                    version_detail
   194→                        .rust_version
   195→                        .as_deref()
   196→                        .unwrap_or("Not specified")
   197→                ));
   198→
   199→                // Dependency weight
   200→                output.push_str("\n## Dependency Weight\n\n");
   201→                output.push_str(&format!(
   202→                    "- **Required dependencies**: {}\n",
   203→                    normal_required.len()
   204→                ));
   205→                if !normal_optional.is_empty() {
   206→                    output.push_str(&format!(
   207→                        "- **Optional dependencies**: {}\n",
   208→                        normal_optional.len()
   209→                    ));
   210→                }
   211→                if !build_deps.is_empty() {
   212→                    output.push_str(&format!("- **Build dependencies**: {}\n", build_deps.len()));
   213→                }
   214→
   215→                // Links
   216→                output.push_str("\n## Links\n\n");
   217→                if let Some(repo) = &crate_data.repository {
   218→                    output.push_str(&format!("- **Repository**: {}\n", repo));
   219→                }
   220→                if let Some(docs) = &crate_data.documentation {
   221→                    output.push_str(&format!("- **Documentation**: {}\n", docs));
   222→                }
   223→                if let Some(home) = &crate_data.homepage {
   224→                    output.push_str(&format!("- **Homepage**: {}\n", home));
   225→                }
   226→
   227→                Ok(CallToolResult::text(output))
   228→            },
   229→        )
   230→        .build()
   231→}
   232→
   233→#[cfg(test)]
   234→mod tests {
   235→    use std::sync::Arc;
   236→    use std::time::Duration;
   237→
   238→    use tokio::sync::RwLock;
   239→    use wiremock::matchers::{method, path};
   240→    use wiremock::{Mock, MockServer, ResponseTemplate};
   241→
   242→    use crate::client::CratesIoClient;
   243→    use crate::client::docsrs::DocsRsClient;
   244→    use crate::client::osv::OsvClient;
   245→    use crate::docs::cache::DocsCache;
   246→    use crate::state::AppState;
   247→
   248→    fn test_state(crates_url: &str, osv_url: &str) -> Arc<AppState> {
   249→        Arc::new(AppState {
   250→            client: CratesIoClient::with_base_url("test", Duration::from_millis(0), crates_url)
   251→                .unwrap(),
   252→            docsrs_client: DocsRsClient::with_base_url("test", crates_url).unwrap(),
   253→            osv_client: OsvClient::with_base_url("test", osv_url).unwrap(),
   254→            docs_cache: DocsCache::new(10, Duration::from_secs(3600)),
   255→            recent_searches: RwLock::new(Vec::new()),
   256→        })
   257→    }
   258→
   259→    #[tokio::test]
   260→    async fn health_check_basic() {
   261→        let crates_server = MockServer::start().await;
   262→        let osv_server = MockServer::start().await;
   263→
   264→        // Crate info
   265→        Mock::given(method("GET"))
   266→            .and(path("/crates/my-crate"))
   267→            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
   268→                "crate": {
   269→                    "name": "my-crate",
   270→                    "max_version": "1.0.0",
   271→                    "description": "A test crate",
   272→                    "downloads": 50000,
   273→                    "recent_downloads": 5000,
   274→                    "created_at": "2024-01-01T00:00:00.000000Z",
   275→                    "updated_at": "2026-02-01T00:00:00.000000Z",
   276→                    "repository": "https://github.com/test/my-crate",
   277→                    "documentation": "https://docs.rs/my-crate"
   278→                },
   279→                "versions": [
   280→                    {"num": "1.0.0", "yanked": false, "created_at": "2026-02-01T00:00:00.000000Z", "downloads": 3000, "license": "MIT"},
   281→                    {"num": "0.9.0", "yanked": false, "created_at": "2025-06-01T00:00:00.000000Z", "downloads": 20000},
   282→                    {"num": "0.1.0", "yanked": false, "created_at": "2024-01-01T00:00:00.000000Z", "downloads": 27000}
   283→                ]
   284→            })))
   285→            .mount(&crates_server)
   286→            .await;
   287→
   288→        // Version detail
   289→        Mock::given(method("GET"))
   290→            .and(path("/crates/my-crate/1.0.0"))
   291→            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
   292→                "version": {
   293→                    "num": "1.0.0",
   294→                    "yanked": false,
   295→                    "created_at": "2026-02-01T00:00:00.000000Z",
   296→                    "downloads": 3000,
   297→                    "license": "MIT OR Apache-2.0",
   298→                    "rust_version": "1.75"
   299→                }
   300→            })))
   301→            .mount(&crates_server)
   302→            .await;
   303→
   304→        // Dependencies
   305→        Mock::given(method("GET"))
   306→            .and(path("/crates/my-crate/1.0.0/dependencies"))
   307→            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
   308→                "dependencies": [
   309→                    {"crate_id": "serde", "req": "^1", "kind": "normal", "optional": false, "version_id": 1},
   310→                    {"crate_id": "tokio", "req": "^1", "kind": "normal", "optional": true, "version_id": 2}
   311→                ]
   312→            })))
   313→            .mount(&crates_server)
   314→            .await;
   315→
   316→        // Reverse deps
   317→        Mock::given(method("GET"))
   318→            .and(path("/crates/my-crate/reverse_dependencies"))
   319→            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
   320→                "dependencies": [],
   321→                "versions": [],
   322→                "meta": {"total": 42}
   323→            })))
   324→            .mount(&crates_server)
   325→            .await;
   326→
   327→        // OSV: no vulnerabilities
   328→        Mock::given(method("POST"))
   329→            .and(path("/query"))
   330→            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
   331→                "vulns": []
   332→            })))
   333→            .mount(&osv_server)
   334→            .await;
   335→
   336→        let state = test_state(&crates_server.uri(), &osv_server.uri());
   337→        let tool = super::build(state);
   338→        let result = tool.call(serde_json::json!({"name": "my-crate"})).await;
   339→
   340→        let text = result.all_text();
   341→        assert!(text.contains("Health Check: my-crate v1.0.0"));
   342→        assert!(text.contains("A test crate"));
   343→        // Maturity
   344→        assert!(text.contains("Total versions"));
   345→        assert!(text.contains("3"));
   346→        assert!(text.contains("Avg release cadence"));
   347→        // Adoption
   348→        assert!(text.contains("50.0K"));
   349→        assert!(text.contains("5.0K"));
   350→        assert!(text.contains("42"));
   351→        // Maintenance
   352→        assert!(text.contains("Last updated"));
   353→        // Security
   354→        assert!(text.contains("None"));
   355→        // Compatibility
   356→        assert!(text.contains("MIT OR Apache-2.0"));
   357→        assert!(text.contains("1.75"));
   358→        // Dependency weight
   359→        assert!(text.contains("Required dependencies"));
   360→        assert!(text.contains("Optional dependencies"));
   361→        // Links
   362→        assert!(text.contains("github.com/test/my-crate"));
   363→        assert!(text.contains("docs.rs/my-crate"));
   364→    }
