   366→    #[tokio::test]
   367→    async fn health_check_with_vulnerabilities() {
   368→        let crates_server = MockServer::start().await;
   369→        let osv_server = MockServer::start().await;
   370→
   371→        Mock::given(method("GET"))
   372→            .and(path("/crates/vuln-crate"))
   373→            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
   374→                "crate": {
   375→                    "name": "vuln-crate",
   376→                    "max_version": "0.1.0",
   377→                    "description": "Has vulns",
   378→                    "downloads": 100,
   379→                    "created_at": "2025-01-01T00:00:00.000000Z",
   380→                    "updated_at": "2025-01-01T00:00:00.000000Z"
   381→                },
   382→                "versions": [
   383→                    {"num": "0.1.0", "yanked": false, "created_at": "2025-01-01T00:00:00.000000Z", "downloads": 100}
   384→                ]
   385→            })))
   386→            .mount(&crates_server)
   387→            .await;
   388→
   389→        Mock::given(method("GET"))
   390→            .and(path("/crates/vuln-crate/0.1.0"))
   391→            .respond_with(ResponseTemplate::new(200).set_body_json(serde_json::json!({
   392→                "version": {
   393→                    "num": "0.1.0",
   394→                    "yanked": false,
