   239→    }
   240→
   241→    /// PUT a JSON body and return a deserialized response. Requires auth.
   242→    pub(crate) async fn put_json<T: DeserializeOwned, B: Serialize>(
   243→        &self,
   244→        path: &str,
   245→        body: &B,
   246→    ) -> Result<T, Error> {
   247→        let token = self.require_auth()?;
   248→        self.throttle().await;
   249→        let url = format!("{}{}", self.base_url, path);
   250→        let resp = self
   251→            .http
