   253→            .header("Authorization", token)
   254→            .json(body)
   255→            .send()
   256→            .await?;
   257→        let resp = Self::check_status(resp, path).await?;
   258→        Ok(resp.json().await?)
   259→    }
   260→
   261→    /// PUT a JSON body, expecting no meaningful response body. Requires auth.
   262→    pub(crate) async fn put_json_ok<B: Serialize>(
   263→        &self,
   264→        path: &str,
   265→        body: &B,
   266→    ) -> Result<(), Error> {
   267→        let token = self.require_auth()?;
