   279→    }
   280→
   281→    /// PUT with no body, returning a deserialized JSON response. Requires auth.
   282→    pub(crate) async fn put_empty<T: DeserializeOwned>(&self, path: &str) -> Result<T, Error> {
   283→        let token = self.require_auth()?;
   284→        self.throttle().await;
