    26→        }
    27→        if let Some(sort) = query.sort {
    28→            params.push(("sort".into(), sort.as_str().into()));
    29→        }
    30→        if let Some(page) = query.page {
    31→            params.push(("page".into(), page.to_string()));
    32→        }
    33→        if let Some(per_page) = query.per_page {
    34→            params.push(("per_page".into(), per_page.to_string()));
    35→        }
    36→        self.get_json_query("/crates", &params).await
    37→    }
