    49→    /// Get reverse dependencies (crates that depend on this crate).
    50→    pub async fn crate_reverse_dependencies(
    51→        &self,
    52→        name: &str,
    53→    ) -> Result<ReverseDependencies, Error> {
    54→        let raw: ReverseDependenciesRaw = self
    55→            .get_json(&format!("/crates/{name}/reverse_dependencies"))
    56→            .await?;
    57→
    58→        // Build a lookup from version ID to (crate_name, version_num)
    59→        let version_map: HashMap<u64, (String, String)> = raw
    60→            .versions
    61→            .into_iter()
    62→            .map(|v| (v.id, (v.krate, v.num)))
    63→            .collect();
    64→
    65→        // Join dependencies with their version info
    66→        let dependencies = raw
    67→            .dependencies
    68→            .into_iter()
    69→            .filter_map(|dep| {
    70→                let version_id = dep.version_id;
    71→                version_map
    72→                    .get(&version_id)
    73→                    .map(|(crate_name, num)| ReverseDependency {
    74→                        crate_version: CrateVersion {
    75→                            crate_name: crate_name.clone(),
    76→                            num: num.clone(),
    77→                        },
    78→                        dependency: dep,
    79→                    })
    80→            })
    81→            .collect();
    82→
    83→        Ok(ReverseDependencies {
    84→            dependencies,
    85→            meta: raw.meta,
    86→        })
    87→    }
    88→
    89→    // ── Authenticated endpoints ─────────────────────────────────────────
    90→
    91→    /// Update crate settings (description, docs, homepage, repository).
    92→    ///
    93→    /// Requires authentication.
    94→    pub async fn update_crate(
    95→        &self,
    96→        name: &str,
    97→        settings: CrateSettings,
    98→    ) -> Result<CrateResponse, Error> {
    99→        let body = UpdateCrateRequest {
   100→            crate_data: settings,
   101→        };
   102→        self.patch_json(&format!("/crates/{name}"), &body).await
   103→    }
   104→
   105→    /// Delete a crate (only if it has a single owner and no dependents).
   106→    ///
   107→    /// Requires authentication.
   108→    pub async fn delete_crate(&self, name: &str) -> Result<(), Error> {
   109→        self.delete_ok(&format!("/crates/{name}")).await
   110→    }
   111→
   112→    /// Follow a crate to receive notifications.
   113→    ///
   114→    /// Requires authentication.
   115→    pub async fn follow_crate(&self, name: &str) -> Result<OkResponse, Error> {
   116→        self.put_empty(&format!("/crates/{name}/follow")).await
   117→    }
   118→
   119→    /// Unfollow a crate.
   120→    ///
   121→    /// Requires authentication.
   122→    pub async fn unfollow_crate(&self, name: &str) -> Result<OkResponse, Error> {
   123→        self.delete_json(&format!("/crates/{name}/follow")).await
   124→    }
   125→
   126→    /// Check if the authenticated user follows a crate.
   127→    ///
   128→    /// Requires authentication.
   129→    pub async fn is_following(&self, name: &str) -> Result<bool, Error> {
   130→        let resp: FollowingResponse = self
   131→            .get_json_auth(&format!("/crates/{name}/following"))
   132→            .await?;
   133→        Ok(resp.following)
   134→    }
