     1→//! OSV.dev API client for vulnerability lookups.
     2→//!
     3→//! Queries the [OSV.dev](https://osv.dev/) API to check Rust crates for known
     4→//! security vulnerabilities aggregated from RustSec, GHSA, and NVD.
     5→
     6→use serde::{Deserialize, Serialize};
     7→
     8→// ── Error ──────────────────────────────────────────────────────────────────
     9→
    10→/// Errors returned by the OSV.dev API client.
    11→#[derive(Debug, thiserror::Error)]
    12→pub enum OsvError {
    13→    /// HTTP transport error.
    14→    #[error("HTTP error: {0}")]
    15→    Http(#[from] reqwest::Error),
    16→
    17→    /// Non-200 response from the API.
    18→    #[error("OSV API error ({status}): {message}")]
    19→    Api { status: u16, message: String },
    20→}
    21→
    22→// ── Response types ─────────────────────────────────────────────────────────
    23→
    24→/// Top-level response from `POST /v1/query`.
    25→#[derive(Debug, Deserialize)]
    26→pub struct OsvQueryResponse {
    27→    pub vulns: Option<Vec<OsvVulnerability>>,
    28→}
    29→
    30→/// A single vulnerability record.
    31→#[derive(Debug, Deserialize)]
    32→pub struct OsvVulnerability {
    33→    /// Advisory ID (e.g. "RUSTSEC-2021-0078", "GHSA-...").
    34→    pub id: String,
    35→    pub summary: Option<String>,
    36→    pub details: Option<String>,
    37→    pub severity: Option<Vec<OsvSeverity>>,
    38→    pub affected: Option<Vec<OsvAffected>>,
    39→    pub references: Option<Vec<OsvReference>>,
    40→}
    41→
    42→/// CVSS severity information.
    43→#[derive(Debug, Deserialize)]
    44→pub struct OsvSeverity {
    45→    /// Severity scheme (e.g. "CVSS_V3", "CVSS_V4").
    46→    #[serde(rename = "type")]
    47→    pub severity_type: String,
    48→    /// CVSS vector string.
    49→    pub score: String,
    50→}
    51→
    52→/// Affected package and version range info.
    53→#[derive(Debug, Deserialize)]
    54→pub struct OsvAffected {
    55→    pub package: Option<OsvPackage>,
    56→    pub ranges: Option<Vec<OsvRange>>,
    57→}
    58→
    59→/// Package identifier within an ecosystem.
    60→#[derive(Debug, Deserialize)]
    61→pub struct OsvPackage {
    62→    pub name: String,
    63→    pub ecosystem: String,
    64→}
    65→
    66→/// A version range that is affected.
    67→#[derive(Debug, Deserialize)]
    68→pub struct OsvRange {
    69→    #[serde(rename = "type")]
    70→    pub range_type: String,
    71→    pub events: Vec<OsvEvent>,
    72→}
    73→
    74→/// A version event (introduced/fixed boundary).
    75→#[derive(Debug, Deserialize)]
    76→pub struct OsvEvent {
    77→    pub introduced: Option<String>,
    78→    pub fixed: Option<String>,
    79→}
    80→
    81→/// A reference link (advisory URL, etc).
    82→#[derive(Debug, Deserialize)]
    83→pub struct OsvReference {
    84→    #[serde(rename = "type")]
    85→    pub ref_type: String,
    86→    pub url: String,
    87→}
    88→
    89→// ── Request body ───────────────────────────────────────────────────────────
    90→
    91→#[derive(Serialize)]
    92→struct OsvQueryRequest<'a> {
    93→    package: OsvPackageQuery<'a>,
    94→    #[serde(skip_serializing_if = "Option::is_none")]
    95→    version: Option<&'a str>,
    96→}
    97→
    98→#[derive(Serialize)]
    99→struct OsvPackageQuery<'a> {
   100→    name: &'a str,
   101→    ecosystem: &'a str,
   102→}
   103→
   104→// ── Client ─────────────────────────────────────────────────────────────────
   105→
   106→/// Async client for the OSV.dev vulnerability API.
   107→pub struct OsvClient {
   108→    http: reqwest::Client,
   109→    base_url: String,
   110→}
   111→
   112→impl OsvClient {
   113→    /// Create a new client with the given user agent.
   114→    pub fn new(user_agent: &str) -> Result<Self, OsvError> {
   115→        Self::with_base_url(user_agent, "https://api.osv.dev/v1")
   116→    }
   117→
   118→    /// Create a new client with a custom base URL (for testing).
   119→    pub fn with_base_url(user_agent: &str, base_url: &str) -> Result<Self, OsvError> {
   120→        let http = reqwest::Client::builder().user_agent(user_agent).build()?;
   121→        Ok(Self {
   122→            http,
   123→            base_url: base_url.trim_end_matches('/').to_string(),
   124→        })
   125→    }
   126→
   127→    /// Query OSV for vulnerabilities affecting a specific package version.
   128→    pub async fn query_package(
   129→        &self,
   130→        name: &str,
   131→        version: &str,
   132→    ) -> Result<OsvQueryResponse, OsvError> {
   133→        let body = OsvQueryRequest {
   134→            package: OsvPackageQuery {
   135→                name,
   136→                ecosystem: "crates.io",
   137→            },
   138→            version: Some(version),
   139→        };
   140→        self.post_query(&body).await
   141→    }
   142→
   143→    /// Query OSV for all known vulnerabilities for a package (any version).
   144→    pub async fn query_package_any(&self, name: &str) -> Result<OsvQueryResponse, OsvError> {
   145→        let body = OsvQueryRequest {
   146→            package: OsvPackageQuery {
   147→                name,
   148→                ecosystem: "crates.io",
   149→            },
   150→            version: None,
   151→        };
   152→        self.post_query(&body).await
   153→    }
   154→
   155→    async fn post_query(&self, body: &OsvQueryRequest<'_>) -> Result<OsvQueryResponse, OsvError> {
   156→        let url = format!("{}/query", self.base_url);
   157→        let resp = self.http.post(&url).json(body).send().await?;
   158→        let status = resp.status();
   159→        if !status.is_success() {
   160→            let message = resp.text().await.unwrap_or_default();
   161→            return Err(OsvError::Api {
   162→                status: status.as_u16(),
   163→                message,
   164→            });
   165→        }
   166→        Ok(resp.json().await?)
   167→    }
   168→}
   169→
   170→// ── Tests ──────────────────────────────────────────────────────────────────
   171→
   172→#[cfg(test)]
   173→mod tests {
   174→    use wiremock::matchers::{body_json, method, path};
